+func TestTmuxClientHelper(t *testing.T) {
+	// With nil client, should return default
+	launcher := NewAgentLauncher()
+	client := launcher.tmuxClient()
+	if client == nil {
+		t.Error("expected non-nil client from tmuxClient()")
+	}
